mapper.update:
UPDATE chat_message
SET status = #{status}, update_time = NOW()
WHERE message_id = #{messageId}

UPDATE chat_message
SET is_read = 1, read_time = NOW(), status = 'read', update_time = NOW()
WHERE receiver_id = #{userId}
  AND sender_id = #{senderId}
  AND is_read = 0
  AND is_deleted = 0

mapper.select:
SELECT COUNT(*) FROM chat_message
WHERE receiver_id = #{userId}
  AND sender_id = #{senderId}
  AND is_read = 0
  AND is_deleted = 0
